challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The 'mongo' database container has exited, causing the PCF (Policy Control Function) to become unresponsive. This leads to failures on the Rx interface, causing the P-CSCF to reject all SIP INVITE requests for new VoNR calls.",
      "primary_suspect_nf": "pcf",
      "probes": [
        {
          "tool": "get_network_status",
          "args_hint": "Check status of 'mongo' container",
          "expected_if_hypothesis_holds": "The 'mongo' container has status 'exited'.",
          "falsifying_observation": "The 'mongo' container is 'running'. This would indicate the database is up and not the root cause of a PCF failure."
        },
        {
          "tool": "read_container_logs",
          "args_hint": "container='pcf', grep='mongo|database|connection refused'",
          "expected_if_hypothesis_holds": "PCF logs show errors attempting to connect to the MongoDB database.",
          "falsifying_observation": "No database connection errors in PCF logs. This would suggest the PCF is either not failing or failing for a reason other than its database."
        },
        {
          "tool": "read_container_logs",
          "args_hint": "container='pcscf', grep='Rx|policy|PCF'",
          "expected_if_hypothesis_holds": "P-CSCF logs show errors related to the Rx interface or inability to get policy from PCF.",
          "falsifying_observation": "No such errors in P-CSCF logs. If P-CSCF is rejecting SIP requests but not logging failures about PCF, the cause of rejection is likely elsewhere."
        }
      ],
      "notes": "This plan directly tests the causal chain asserted in the hypothesis: the database is down (probe 1), which causes the PCF to fail (probe 2), which in turn causes the P-CSCF to fail (probe 3)."
    },
    {
      "hypothesis_id": "h2",
      "hypothesis_statement": "A network partition exists between the P-CSCF and the PCF, preventing the P-CSCF from obtaining QoS policy authorization for SIP sessions.",
      "primary_suspect_nf": "pcf",
      "probes": [
        {
          "tool": "measure_rtt",
          "args_hint": "from='pcscf', to_ip='pcf_ip'",
          "expected_if_hypothesis_holds": "100% packet loss or extremely high RTT, indicating a partition.",
          "falsifying_observation": "Clean, low RTT (<5ms). This would directly disprove a network partition between the two components."
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from='pcf', to_ip='pcscf_ip'",
          "expected_if_hypothesis_holds": "100% packet loss (symmetric partition).",
          "falsifying_observation": "Clean, low RTT (<5ms). This triangulates the first probe and confirms bi-directional connectivity, disproving a partition."
        },
        {
          "tool": "get_network_status",
          "args_hint": "Check status of 'pcf' and 'mongo' containers",
          "expected_if_hypothesis_holds": "Both 'pcf' and 'mongo' containers are 'running', but isolated.",
          "falsifying_observation": "Either 'pcf' or 'mongo' is in an 'exited' state. This would falsify the 'partition' hypothesis and support the 'container down' hypothesis (h1)."
        }
      ],
      "notes": "This plan focuses on verifying the network-level isolation claimed in the hypothesis. Probes 1 and 2 test the primary link from both directions for triangulation. Probe 3 helps disambiguate this hypothesis from h1 by checking container health."
    }
  ]
}

